using TMPro;
using UnityEngine;

/// <summary>
/// Prompt genérico de interacção do HUD (Tarefa #32) — ex: "Aperta [E] para
/// falar", "Aperta [E] para abrir", "Aperta [E] para apanhar". Qualquer
/// sistema (NpcController, alavancas, baús, objectos agarráveis, etc.) chama
/// <see cref="Show(string)"/> quando o player entra no alcance e
/// <see cref="Hide"/> quando sai (ou a interacção deixa de ser possível).
///
/// Singleton simples (Instance) — diferente do padrão
/// EnsureExists/DontDestroyOnLoad dos outros singletons (PlayerProgress,
/// WorldState, ...) porque este componente faz parte do Canvas do HUD de cada
/// cena, não precisa de persistir entre cenas.
/// </summary>
public class InteractionPromptUI : MonoBehaviour
{
    public static InteractionPromptUI Instance { get; private set; }

    [SerializeField] private GameObject root;
    [SerializeField] private TMP_Text promptText;

    private void Awake()
    {
        Instance = this;
        if (root != null) root.SetActive(false);
    }

    private void OnDestroy()
    {
        if (Instance == this) Instance = null;
    }

    /// <summary>Mostra o prompt com o texto dado (ex: "Aperta [E] para falar").</summary>
    public void Show(string text)
    {
        if (promptText != null) promptText.text = text;
        if (root != null) root.SetActive(true);
    }

    public void Hide()
    {
        if (root != null) root.SetActive(false);
    }
}
